<template>
  <div>
    <div v-if="mounted" class="row" style="border-style: none; height: 55px !important">
      <div v-if="ifPdf" class="col-md-12">
        <!--  -->
        <button style="width: 220px" class="btn btn-secondary btn-sm pull-left" @click.prevent="Nazad()">
          <span class="fa fa-step-backward"></span>
          {{ " NAZAD" }}
        </button>
        <!--  -->
        <button v-show="$store.state.userId != 'slavica'" :disabled="popust.toString().trim() == '' || total.toString().trim() == ''" style="width: 220px" v-if="izbor === 'Popust'" class="btn btn-secondary btn-sm pull-right" @click.prevent="Popust()">
          <span class="fa fa-credit-card"></span>
          {{ " RAČUN" }}
        </button>
        <!--  -->
        <button v-show="$store.state.userId != 'slavica'" :disabled="popust.toString().trim() == '' || total.toString().trim() == ''" style="width: 220px" v-if="izbor === 'Cijena'" class="btn btn-secondary btn-sm pull-right" @click.prevent="Cijena()">
          <span class="fa fa-credit-card"></span>
          {{ " RAČUN" }}
        </button>
        <!--  -->
        <div class="form-group with-icon-left pull-left" style="padding-left: 2%">
          <vuestic-simple-select v-show="$store.state.userId != 'slavica'"
            class="form-group with-icon-right"
            label="Izbor"
            v-model="izbor"
            name="izbor"
            required
            title=" "
            ref="izbor"
            v-bind:options="['Cijena', 'Popust']"
          ></vuestic-simple-select>
        </div>

        <div v-show="$store.state.userId != 'slavica'" class="form-group with-icon-left pull-right" style="padding-right: 2%">
          <!--  -->
          <div v-if="izbor === 'Cijena'" class="input-group">
            <input id="input-icon-total" name="input-icon-total" v-model="total" title=" "/>
            <i class="fa fa-credit-card icon-left input-icon"></i>
            <label class="control-label" for="input-icon-total">{{ "Za platiti" }}</label>
            <i class="bar"></i>
          </div>
          <!--  -->
          <div v-if="izbor === 'Popust'" class="input-group">
            <input id="input-icon-popust" name="input-icon-popust" v-model="popust" title=" "/>
            <i class="fa fa-percent icon-left input-icon"></i>
            <label class="control-label" for="input-icon-popust">{{ "Unesite popust" }}</label>
            <i class="bar"></i>
          </div>
          <!--  -->
        </div>
      </div>
    </div>

    <div class="row">
      <div class="col-md-12">
        <hr v-show="mounted" />
        <div class="d-flex flex-column align-items-center justify-content-between down-container">
          <embed src id="pdf" style="width: 100%; height: 800px; visibility: hidden" type="application/pdf"/>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

import router from "../../router";
import { http } from "../../../config/config.js";
import { server } from "../../../config/config.js";

export default {
  name: "predracun",
  props: ["id"],

  data() {
    return {
      ifPdf: false,
      mounted: false,
      text: "Za platiti: ",
      izbor: "Cijena",
      link: "",
      // 
      total: 0,
      originalTotal: 0,
      // 
      popust: 0,
      originalPopust: 0,
    };
  },

  mounted() {

    this.mounted = false;   

    http
      .post("racuni/get", { // GET
        token: this.$store.state.token,
        site: this.$store.state.site,
        patient: this.$route.params.id,
        uzorci: this.$route.query.uzorci,
        popust: this.popust,
        total: this.total,
      })
      .then((res) => {
        if (res.data.success) {
          console.log("GET")
          console.log(res.data);

          this.ifPdf = true;

          document.getElementById("pdf").style.visibility = "visible";
          document.getElementById("pdf").src =
            server + "racuni/" + res.data.link;

          this.total = res.data.total;
          this.originalTotal = res.data.nodiscount;

          this.popust = res.data.discount;
          this.originalPopust = res.data.discount;

          this.link = res.data.link;
          this.mounted = true;
        } else {
          //
        }
      });
  },
  watch: {
    popust() {
      if (this.izbor === "Popust") {
        if (isNaN(this.popust) || this.popust.trim() === "") {
          console.log("Vrijednost nije validan broj.")
        } else if (!isNaN(this.popust)) {
          
          this.total = parseFloat(
            Number(this.originalTotal * ((100 - this.popust) / 100)).toFixed(2)
          );

          this.popust = parseFloat(this.popust.toFixed(2));

        } else {
          //
        }
      }
    },
    total() {
      if (this.izbor === "Cijena") {
        if (isNaN(this.total)) {
        console.log("Vrijednost nije validan broj.")
        } else if (!isNaN(this.total)) {

          this.popust = parseFloat(
            Number(
              ((this.originalTotal - this.total) / this.originalTotal) * 100
            ).toFixed(2)
          );

          this.total = parseFloat(this.total.toFixed(2));

        } else {
          //
        }
      }
    },
  },
  methods: {

    Nazad: function () {
      this.ifPdf = false;
      this.mounted = false;
      this.total = 0;
      this.originalTotal = 0;
      this.popust = 0;
      this.originalPopust = 0;
      this.link = "";
      router.push("/obrada/pregled/" + "?sekcija=" + "SVE");
    },

    Popust() {
      if (!isNaN(this.total) && !isNaN(this.popust) && Number(this.popust) >= 0 && Number(this.popust) <= 100) {
        // console.log(this.popust)
        // console.log(this.total)
        http
          .post("racuni/popust", {
            token: this.$store.state.token,
            site: this.$store.state.site,
            patient: this.$route.params.id,
            uzorci: this.$route.query.uzorci,
            popust: this.popust,
            total: this.total,
          })
          .then((res) => {
            if (res.data.success) {
              console.log("Popust")
              console.log(res.data);

              this.ifPdf = true;

              document.getElementById("pdf").style.visibility = "visible";
              document.getElementById("pdf").src =
                server + "racuni/" + res.data.link;

              this.total = res.data.total;
              // this.originalTotal = res.data.total;

              this.popust = res.data.discount;
              // this.originalPopust = res.data.discount

              this.link = res.data.link;
              this.mounted = true;
            } else {
              //
            }
          });
      } else {
        console.warn("Invalid Data.")
      }
    },

    Cijena() {
      if (!isNaN(this.popust) && !isNaN(this.total) && Number(this.total) <= Number(this.originalTotal)) {
        // console.log(this.popust)
        // console.log(this.total)
        http
          .post("racuni/cijena", {
            token: this.$store.state.token,
            site: this.$store.state.site,
            patient: this.$route.params.id,
            uzorci: this.$route.query.uzorci,
            popust: this.popust,
            total: this.total,
          })
          .then((res) => {
            if (res.data.success) {
              console.log("Cijena")
              console.log(res.data);

              this.ifPdf = true;

              document.getElementById("pdf").style.visibility = "visible";
              document.getElementById("pdf").src =
                server + "racuni/" + res.data.link;

              this.total = res.data.total;
              // this.originalTotal = res.data.total;

              this.popust = res.data.discount;
              // this.originalPopust = res.data.discount

              this.link = res.data.link;
              this.mounted = true;
            } else {
              //
            }
          });
      } else {
        console.warn("Invalid Data.")
      }
    },
  },
};
</script>

<style lang="scss">
@import "../../sass/_variables.scss";
@import "../../sass/_toasts";

.stats-number,
.stats-title {
  line-height: 1;
}

.info-widget-inner {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  position: relative;
  width: 100%;
  &.has-chart {
    justify-content: space-between;
  }
  .stats {
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    height: 100%;
  }
}

.stats-number {
  position: relative;
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  font-size: 1.7rem;
  margin-bottom: 0.5rem;
  .stats-icon {
    font-size: 1.5625rem;
    position: absolute;
    top: 0.625rem;
    left: -1.25rem;
    &.icon-wide {
      left: -1.875rem;
    }
  }
}

.color-icon-label-table {
  td:first-child {
    width: 1rem;
  }
}

.brand-danger {
  background-color: #db76df;
  color: $white;
  box-shadow: $widget-danger-shadow;
}

.info-widget {
  border-top: $info-widget-border;
  &.brand-info {
    border-top-color: $brand-info;
  }
  &.brand-danger {
    border-top-color: #db76df;
  }
}
</style>




